"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[4001],{8883(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"v0.5.0","metadata":{"permalink":"/gradgen/blog/v0.5.0","editUrl":"https://github.com/QUB-ASL/gradgen/tree/main/docs/website/blog/2026-05-02-v0.5.0.md","source":"@site/blog/2026-05-02-v0.5.0.md","title":"What\'s new in v0.5.0","description":"Gradgen v0.5.0 adds embeddable Rust code generation improvements, shorter OCP-generated code, and better support for OpEn integration.","date":"2026-05-02T00:00:00.000Z","tags":[{"inline":false,"label":"New version","permalink":"/gradgen/blog/tags/new_version","description":"Release of new version"}],"readingTime":0.58,"hasTruncateMarker":true,"authors":[{"name":"Pantelis Sopasakis","title":"Lecturer, QUB","url":"https://github.com/alphaville","page":{"permalink":"/gradgen/blog/authors/pantelis"},"imageURL":"https://www.qub.ac.uk/schools/media/Media1218037smxx.png","key":"pantelis"}],"frontMatter":{"slug":"v0.5.0","title":"What\'s new in v0.5.0","authors":["pantelis"],"tags":["release"],"description":"Gradgen v0.5.0 adds embeddable Rust code generation improvements, shorter OCP-generated code, and better support for OpEn integration.","keywords":["gradgen","rust code generation","automatic differentiation","no_std","optimal control"]},"unlisted":false,"nextItem":{"title":"API docs","permalink":"/gradgen/blog/api-docs"}},"content":"[Gradgen v0.5.0](https://github.com/QUB-ASL/gradgen/releases/tag/v0.5.0) brings significant changes and new functionality. \\nMost importantly, it brings us very close to a full integration \\nwith [OpEn](https://alphaville.github.io/optimization-engine/),\\nthis means that:\\n- We\'ll be generating pure Rust code, fully embeddable (`#[no-std]`),\\n  safe, with support for both single and double precision arithmetic\\n- The generated code for optimal control problems will be significantly shorter.\\n  This will decrease significantly the compilation times (from minutes to seconds)\\n\\n\x3c!-- truncate --\x3e\\n\\nGradgen v0.5.0 can be installed using `pip`:\\n\\n```bash\\npip install gradgen==0.5.0\\n```\\n\\nUpcoming developments:\\n- Improved documentation and examples, including Python notebooks on Google Colab and demos\\n- Benchmarks\\n- Support for the forward-backward envelope in optimal control problems"},{"id":"api-docs","metadata":{"permalink":"/gradgen/blog/api-docs","editUrl":"https://github.com/QUB-ASL/gradgen/tree/main/docs/website/blog/2026-04-30-api-docs.md","source":"@site/blog/2026-04-30-api-docs.md","title":"API docs","description":"The API docs of gradgen are now available here. The API docs have been generated automatically from the docstrings in the code using Sphinx.","date":"2026-04-30T00:00:00.000Z","tags":[{"inline":false,"label":"New version","permalink":"/gradgen/blog/tags/new_version","description":"Release of new version"}],"readingTime":0.18,"hasTruncateMarker":false,"authors":[{"name":"Pantelis Sopasakis","title":"Lecturer, QUB","url":"https://github.com/alphaville","page":{"permalink":"/gradgen/blog/authors/pantelis"},"imageURL":"https://www.qub.ac.uk/schools/media/Media1218037smxx.png","key":"pantelis"}],"frontMatter":{"slug":"api-docs","title":"API docs","authors":["pantelis"],"tags":["release"]},"unlisted":false,"prevItem":{"title":"What\'s new in v0.5.0","permalink":"/gradgen/blog/v0.5.0"},"nextItem":{"title":"Gradgen revival","permalink":"/gradgen/blog/first-blog-post"}},"content":"The API docs of gradgen are now available [here](https://qub-asl.github.io/gradgen/api-dox/). The API docs have been generated automatically from the docstrings in the code using [Sphinx](https://www.sphinx-doc.org/en/master/)."},{"id":"first-blog-post","metadata":{"permalink":"/gradgen/blog/first-blog-post","editUrl":"https://github.com/QUB-ASL/gradgen/tree/main/docs/website/blog/2026-03-31-first-blog-post.md","source":"@site/blog/2026-03-31-first-blog-post.md","title":"Gradgen revival","description":"Welcome to this brand new website of gradgen: your Python module for automatic differentiation and truly embedded Rust code generation.","date":"2026-03-31T00:00:00.000Z","tags":[{"inline":false,"label":"New version","permalink":"/gradgen/blog/tags/new_version","description":"Release of new version"}],"readingTime":0.65,"hasTruncateMarker":true,"authors":[{"name":"Pantelis Sopasakis","title":"Lecturer, QUB","url":"https://github.com/alphaville","page":{"permalink":"/gradgen/blog/authors/pantelis"},"imageURL":"https://www.qub.ac.uk/schools/media/Media1218037smxx.png","key":"pantelis"}],"frontMatter":{"slug":"first-blog-post","title":"Gradgen revival","authors":["pantelis"],"tags":["release"]},"unlisted":false,"prevItem":{"title":"API docs","permalink":"/gradgen/blog/api-docs"}},"content":"Welcome to this brand new website of gradgen: your Python module for automatic differentiation and truly embedded Rust code generation.\\n\\nGradgen v0.3 brings two significant changes:\\n\\n1. It has been redesigned to generate **Rust crates**, optionally marked with `#[no_std]` so you can use them directly in your embedded applications\\n2. It comes with specialised code generation mechanisms for **optimal control** leading to Rust code that **does not increase in size** with the prediction horizon\\n\\n\x3c!-- truncate --\x3e\\n\\nWe are already working on gradgen v0.3 which will bring one more significant change: support for high-order functions like **map**, **zip**, and **reduce**, which will improve code generation even more. \\n\\nOur goal is to exploit the structure of a function, its gradient, and Hessian to generate more efficient, elegant, and fast Rust code."}]}}')}}]);